from openai import OpenAI
client = OpenAI()

# Define tools with hosted endpoints
tools = [{
    "name": "search",
    "url": "https://your-tools.modal.run/search",
    "headers": {"Authorization": "Bearer TOKEN"}
}]

# Define grader for rewards
grader = {
    "type": "model",
    "model": "gpt-4o",
    "prompt": "Evaluate agent answer vs ground truth..."
}

# Start Agent RFT job
job = client.fine_tuning.jobs.create(
    training_file="file-abc123",
    model="gpt-4o-2024-08-06",
    method="rft",
    rft={
        "tools": tools,
        "grader": grader,
        "hyperparameters": {
            "compute_multiplier": 1
        }
    }
)
